/** Props for the {@link ProtectedRoute} component. */
interface ProtectedRouteProps {
    children: ReactNode;
    /** Where to redirect if not authenticated. Default: renders fallback. */
    redirectTo?: string;
    /** Required role(s). If set, user must have one of these roles. */
    roles?: string[];
    /** Custom loading component */
    loadingComponent?: ReactNode;
    /** Custom unauthorized component (wrong role) */
    unauthorizedComponent?: ReactNode;
    /** Custom unauthenticated component (not logged in) */
    unauthenticatedComponent?: ReactNode;
}
/**
 * Component that protects its children from unauthenticated access.
 * Supports role-based access control.
 *
 * @example
 * ```tsx
 * // Basic protection
 * <ProtectedRoute>
 *   <Dashboard />
 * </ProtectedRoute>
 * ```
 *
 * @example
 * ```tsx
 * // With redirect (requires react-router or similar)
 * <ProtectedRoute redirectTo="/login">
 *   <Dashboard />
 * </ProtectedRoute>
 * ```
 *
 * @example
 * ```tsx
 * // Admin only
 * <ProtectedRoute roles={['admin']}>
 *   <AdminPanel />
 * </ProtectedRoute>
 * ```
 *
 * @example
 * ```tsx
 * // Custom components
 * <ProtectedRoute
 *   loadingComponent={<MySpinner />}
 *   unauthenticatedComponent={<LoginPrompt />}
 *   unauthorizedComponent={<AccessDenied />}
 *   roles={['admin', 'editor']}
 * >
 *   <EditPage />
 * </ProtectedRoute>
 * ```
 */
declare function ProtectedRoute({ children, redirectTo, roles, loadingComponent, unauthorizedComponent, unauthenticatedComponent, }: ProtectedRouteProps): react_jsx_runtime.JSX.Element | null;

